mapper.update:
UPDATE room
SET room_name = #{roomName},
    location = #{location},
    capacity = #{capacity}
WHERE room_no = #{roomNo}

UPDATE room
SET status = 'DISABLED'
WHERE room_no = #{roomNo}

mapper.select:
SELECT COUNT(*)
FROM room_reservation
WHERE room_no = #{roomNo}
  AND reservation_date = #{reservationDate}
  AND status = 'RESERVED'
  AND (
      (#{seatNo} IS NOT NULL AND seat_no = #{seatNo})
      OR (#{seatNo} IS NULL AND seat_no IS NULL)
  )
  AND start_time < #{endTime}
  AND end_time > #{startTime}
